class NimBuffer {
 public:
  NimBuffer() = default;
  NimBuffer(void* p, int32_t n) noexcept : p_(p), n_(n) {}
  NimBuffer(NimBuffer&& o) noexcept : p_(o.p_), n_(o.n_) { o.p_ = nullptr; o.n_ = 0; }
  NimBuffer& operator=(NimBuffer&& o) noexcept {
    if (this != &o) { reset(); p_ = o.p_; n_ = o.n_; o.p_ = nullptr; o.n_ = 0; }
    return *this;
  }
  NimBuffer(const NimBuffer&) = delete;
  NimBuffer& operator=(const NimBuffer&) = delete;
  ~NimBuffer() { reset(); }
  void reset() noexcept {
    if (p_) { typemappingtestlib_freeBuffer(p_); p_ = nullptr; n_ = 0; }
  }
  bool empty() const noexcept { return p_ == nullptr || n_ <= 0; }
  std::span<const std::uint8_t> view() const noexcept {
    return {static_cast<const std::uint8_t*>(p_),
            static_cast<std::size_t>(n_ > 0 ? n_ : 0)};
  }
 private:
  void* p_ = nullptr;
  int32_t n_ = 0;
};

struct CountingSink {
  using value_type = std::uint8_t;
  std::size_t* count;
  explicit CountingSink(std::size_t& c) noexcept : count(&c) {}
  void append(const std::uint8_t*, std::size_t n) noexcept { *count += n; }
  void push_back(std::uint8_t) noexcept { ++*count; }
  void flush() noexcept {}
};

struct SpanSink {
  using value_type = std::uint8_t;
  std::uint8_t* dst;
  std::size_t cap;
  std::size_t* pos;
  SpanSink(std::uint8_t* d, std::size_t c, std::size_t& p) noexcept
      : dst(d), cap(c), pos(&p) {}
  void append(const std::uint8_t* s, std::size_t n) noexcept {
    std::memcpy(dst + *pos, s, n); *pos += n;
  }
  void push_back(std::uint8_t b) noexcept { dst[(*pos)++] = b; }
  void flush() noexcept {}
};

template <class T>
std::size_t cborEncodedSize(const T& v) {
  std::size_t n = 0;
  jsoncons::cbor::basic_cbor_encoder<CountingSink> enc{CountingSink{n}};
  auto result = jsoncons::reflect::encode_traits<T>::try_encode(
      jsoncons::make_alloc_set(), v, enc);
  if (!result) throw std::system_error(result.error(), "cbor counting pass");
  enc.flush();
  return n;
}

template <class T>
void cborEncodeInto(const T& v, std::uint8_t* dst, std::size_t cap) {
  std::size_t pos = 0;
  jsoncons::cbor::basic_cbor_encoder<SpanSink> enc{SpanSink{dst, cap, pos}};
  auto result = jsoncons::reflect::encode_traits<T>::try_encode(
      jsoncons::make_alloc_set(), v, enc);
  if (!result) throw std::system_error(result.error(), "cbor write pass");
  enc.flush();
}

inline std::pair<int32_t, NimBuffer>
rawCall(uint32_t ctx, std::string& lastError,
        const char* apiName, const std::uint8_t* in, std::size_t inLen) {
  if (ctx == 0) {
    lastError = "library context is not initialised";
    return {-1, NimBuffer{}};
  }
  void* inBuf = nullptr;
  if (inLen > 0) {
    inBuf = typemappingtestlib_allocBuffer(static_cast<int32_t>(inLen));
    if (!inBuf) { lastError = "allocBuffer failed"; return {-1, NimBuffer{}}; }
    std::memcpy(inBuf, in, inLen);
  }
  void* respBuf = nullptr;
  int32_t respLen = 0;
  const int32_t status = typemappingtestlib_call(
      ctx, apiName, inBuf, static_cast<int32_t>(inLen), &respBuf, &respLen);
  NimBuffer resp{respBuf, respLen};
  if (status != 0) {
    if (status == -4 && !resp.empty()) {
      auto v = resp.view();
      lastError.assign(reinterpret_cast<const char*>(v.data()), v.size());
    } else {
      lastError = std::string("framework error: ") +
                  std::to_string(status);
    }
    return {status, std::move(resp)};
  }
  return {0, std::move(resp)};
}

inline std::pair<int32_t, NimBuffer>
rawCallOwned(uint32_t ctx, std::string& lastError,
             const char* apiName, void* nimInBuf, std::size_t inLen) {
  if (ctx == 0) {
    if (nimInBuf) typemappingtestlib_freeBuffer(nimInBuf);
    lastError = "library context is not initialised";
    return {-1, NimBuffer{}};
  }
  void* respBuf = nullptr;
  int32_t respLen = 0;
  const int32_t status = typemappingtestlib_call(
      ctx, apiName, nimInBuf, static_cast<int32_t>(inLen), &respBuf, &respLen);
  NimBuffer resp{respBuf, respLen};
  if (status != 0) {
    if (status == -4 && !resp.empty()) {
      auto v = resp.view();
      lastError.assign(reinterpret_cast<const char*>(v.data()), v.size());
    } else {
      lastError = std::string("framework error: ") +
                  std::to_string(status);
    }
    return {status, std::move(resp)};
  }
  return {0, std::move(resp)};
}

template <typename Owner, typename Traits>
class EventDispatcher {
 public:
  using Callback = typename Traits::template Callback<Owner>;
  using EventStruct = typename Traits::EventStruct;

  explicit EventDispatcher(Owner& owner) noexcept : owner_(&owner) {}
  EventDispatcher(const EventDispatcher&) = delete;
  EventDispatcher& operator=(const EventDispatcher&) = delete;
  EventDispatcher(EventDispatcher&&) = delete;
  EventDispatcher& operator=(EventDispatcher&&) = delete;
  ~EventDispatcher() { clear(); }

  uint64_t add(Callback fn) noexcept {
    std::lock_guard<std::mutex> lock(mutex_);
    if (!owner_ || owner_->ctx() == 0 || !fn) return 0;
    if (nativeHandle_ == 0) {
      nativeHandle_ = Traits::registerWithC(
          owner_->ctx(), &EventDispatcher::trampoline, static_cast<void*>(this));
      if (nativeHandle_ == 0) return 0;
    }
    const uint64_t localHandle = nextLocalHandle_++;
    try {
      callbacks_.emplace(localHandle, std::move(fn));
      return localHandle;
    } catch (...) {
      if (callbacks_.empty() && nativeHandle_ != 0) {
        Traits::unregisterWithC(owner_->ctx(), nativeHandle_);
        nativeHandle_ = 0;
      }
      return 0;
    }
  }

  void remove(uint64_t localHandle) noexcept {
    std::lock_guard<std::mutex> lock(mutex_);
    callbacks_.erase(localHandle);
    if (callbacks_.empty() && nativeHandle_ != 0) {
      if (owner_ && owner_->ctx() != 0)
        Traits::unregisterWithC(owner_->ctx(), nativeHandle_);
      nativeHandle_ = 0;
    }
  }

  void clear() noexcept {
    std::lock_guard<std::mutex> lock(mutex_);
    callbacks_.clear();
    if (nativeHandle_ != 0) {
      if (owner_ && owner_->ctx() != 0)
        Traits::unregisterWithC(owner_->ctx(), nativeHandle_);
      nativeHandle_ = 0;
    }
  }

 private:
  static void trampoline(uint32_t ctx, const char* /*eventName*/,
                         const void* payloadBuf, int32_t payloadLen,
                         void* userData) noexcept {
    auto* self = static_cast<EventDispatcher*>(userData);
    if (!self || !payloadBuf || payloadLen <= 0) return;
    EventStruct evt;
    try {
      std::span<const std::uint8_t> v{
          static_cast<const std::uint8_t*>(payloadBuf),
          static_cast<std::size_t>(payloadLen)};
      evt = jsoncons::cbor::decode_cbor<EventStruct>(v.begin(), v.end());
    } catch (...) { return; }
    self->deliver(ctx, evt);
  }

  void deliver(uint32_t ctx, const EventStruct& evt) noexcept {
    std::vector<Callback> snapshot;
    {
      std::lock_guard<std::mutex> lock(mutex_);
      if (!owner_ || ctx != owner_->ctx()) return;
      try {
        snapshot.reserve(callbacks_.size());
        for (const auto& [id, fn] : callbacks_) if (fn) snapshot.push_back(fn);
      } catch (...) { return; }
    }
    for (const auto& fn : snapshot) Traits::invoke(fn, *owner_, evt);
  }

  Owner* owner_ = nullptr;
  std::mutex mutex_;
  std::unordered_map<uint64_t, Callback> callbacks_;
  uint64_t nativeHandle_ = 0;
  uint64_t nextLocalHandle_ = 1;
};

struct VoidPingEventTraits {
  using EventStruct = jsoncons::json;

  template <typename Owner>
  using Callback = std::function<void(Owner&)>;

  static uint64_t registerWithC(uint32_t ctx,
      void (*cb)(uint32_t, const char*, const void*, int32_t, void*),
      void* userData) noexcept {
    return typemappingtestlib_subscribe(ctx, "void_ping", cb, userData);
  }

  static void unregisterWithC(uint32_t ctx, uint64_t handle) noexcept {
    typemappingtestlib_unsubscribe(ctx, "void_ping", handle);
  }

  template <typename Owner>
  static void invoke(const Callback<Owner>& fn, Owner& owner,
                     const jsoncons::json& evt) noexcept {
    try {
      fn(owner);
    } catch (...) {}
  }
};

