inline uint64_t Typemappingtestlib::onSimpleIntEvent(SimpleIntEventCallback fn) noexcept {
  return simple_int_eventDispatcher_->add(std::move(fn));
}

inline void Typemappingtestlib::offSimpleIntEvent(uint64_t handle) noexcept {
  if (handle == 0) simple_int_eventDispatcher_->clear();
  else simple_int_eventDispatcher_->remove(handle);
}

inline std::string Typemappingtestlib::listApis() {
  void* buf = nullptr;
  int32_t len = 0;
  const int32_t status = typemappingtestlib_listApis(&buf, &len);
  detail::NimBuffer nb{buf, len};
  if (status != 0) return {};
  if (nb.empty()) return {};
  auto v = nb.view();
  return std::string(reinterpret_cast<const char*>(v.data()), v.size());
}

inline std::string Typemappingtestlib::getSchema() {
  void* buf = nullptr;
  int32_t len = 0;
  const int32_t status = typemappingtestlib_getSchema(&buf, &len);
  detail::NimBuffer nb{buf, len};
  if (status != 0) return {};
  if (nb.empty()) return {};
  auto v = nb.view();
  return std::string(reinterpret_cast<const char*>(v.data()), v.size());
}

